import type { IHostStore, ISerializer, IStorage } from './types'

/**
 * Create a empty storage.
 * @returns
 */
export const createEmptyStorage = <T>(): IStorage<T> => ({
  load: () => Promise.resolve(null),
  save: () => Promise.resolve(),
})

/**
 * Create a storage.
 *
 * @param store
 * @param key
 * @param serializer
 * @returns
 */
export const createStorage = <T>(
  store: IHostStore,
  key: string,
  serializer: ISerializer<T>,
): IStorage<T> => ({
  load: async (): Promise<T | null> => {
    const content = await store.get(key)
    if (content == null) return null
    return serializer.parse(content)
  },
  save: async (data: T): Promise<void> => {
    const content: string = serializer.stringify(data)
    await store.set(key, content)
  },
})
