import create from 'zustand'
import { isPromise } from '@/core/util/is'
import { storage } from './_storage'
import { defaultState } from './constant'
import type { ISiteState } from './state'

export interface ISiteStore {
  state: ISiteState
  patch(state: Partial<ISiteState>): Promise<void>
  patchPreference(preference: Partial<ISiteState['preference']>): Promise<void>
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
export const createSiteStore = (initialState: ISiteState | Promise<ISiteState>) => {
  return create<ISiteStore>((set, get) => {
    let state: ISiteState = defaultState
    if (isPromise(initialState)) {
      void initialState.then(s => {
        if (get().state === state) set({ state: s })
      })
    } else {
      state = initialState
    }

    return {
      state,
      patch: async state => {
        const { state: previousState } = get()
        const nextState: ISiteState = { ...previousState, ...state }
        set(() => ({ state: nextState }))
        await storage.save(nextState)
      },
      patchPreference: preference => {
        const { state, patch } = get()
        return patch({ preference: { ...state.preference, ...preference } })
      },
    }
  })
}
