import type { Theme } from '@yozora/core-react-theme'
import { storage } from './_storage'
import { defaultState } from './constant'

export interface ISiteState {
  author: {
    name: string
    motto: string
    github: string
    rss: string
    home: string
  }
  copyright: {
    date: string
  }
  title: string
  description: string
  siteUrl: string
  preference: {
    theme: Theme
  }
}

export const initialState = async (): Promise<ISiteState> => {
  const customData = await storage.load()

  return {
    ...defaultState,
    ...customData,
    ...customData,
    author: {
      ...defaultState.author,
      ...customData?.author,
    },
    copyright: {
      ...defaultState.copyright,
      ...customData?.copyright,
    },
    preference: {
      ...defaultState.preference,
      ...customData?.preference,
    },
  }
}
